export function useLisensi() {
let mydata  = [];
let mydata2 = [];
$.ajax({
    url:  tatiyeNet.hostName+"/api/license",
    method: 'GET',
    datatype: "json",
    async: false,
    success: function(data){
             var add=JSON.stringify(data, null, 10);
             mydata = JSON.parse(add);      
    }
  });
    $.ajax({
         url: useLisensiApi+"/api/license/"+mydata.key,
        method: 'GET',
        datatype: "json",
        async: false,
        success: function(data){
           
            if (data.status=='active') {
                 Cookies.set('trial', data.sso, { expires: 10000});
            } else if (data.status=='expair') {
                Cookies.set('trial', data.sso, { expires: 10000});
            } else {
                 Cookies.set('trial', '', { expires: 10000});

            }
            // console.log(data.status)
                 var add=JSON.stringify(data, null, 10);
                 mydata2 = JSON.parse(add);      
        }
      });
    return mydata2;
}
