export function Firebase (e) {
    // if (appSSO.userid) {
            let db=appfirebase.database().ref(e.tabel[0]);
            if (e.tabel[1]=='insert') {
              const d = new Date();
              let time = d.getTime();

              let useragent = {
                  id:appSSO.userid+''+time,
                  userid:appSSO.userid,
                  avatar:appSSO.avatar,
                  username:appSSO.name,
                  date:setDateTime("EN"),
                  time:setDateTime("jam")
              };

             let margeData = Object.assign({}, e.data,useragent);

              db.child(time).set(margeData);
            } else if (e.tabel[1]=='update') {
                db.on("value", function (select) {
                    select.forEach(function(row){
                        var post = row.val();
                        if (post.id==e.data.id) {
                            db.child(row.key).update(e.data);
                        }
                    });
                });
            } else  if (e.tabel[1]=='delete') {
                db.on("value", function (select) {
                    select.forEach(function(row){
                        var post = row.val();
                        if (post.id==e.id) {
                            db.child(row.key).remove();
                        }
                    });
                });  
            } else  if (e.tabel[1]=='select') {    
                 return db;
            }
    // } else {
    //   return false;
    // }

   
}



let db;
const dbRequest = indexedDB.open('ngorey', 1);
dbRequest.onsuccess = function(event) {
  db = event.target.result;
};

dbRequest.onupgradeneeded = function(event) {
  db = event.target.result;

  const objStore = db.createObjectStore('data', { keyPath: 'id' });

  objStore.transaction.oncomplete = function(event) {
    const productsStore = db
      .transaction('data', 'readwrite')
      .objectStore('data');
    productsStore.add({
      id: 'index',
      baseLink: BASE_URL,
      created: new Date(),
      tags: ['Expensive', 'Luxury']
    });
  };
};

dbRequest.onerror = function(event) {
  console.log('ERROR!');
};



