export function setRouter(main) {
 $.each(main.selector,function(key1, row){
   const setID = document.querySelectorAll('#'+row+" a"); 
                $(setID).each(function( index ) {
                 if ($(this).attr("onclick")) {
                 } else {
                    $(this).attr("onclick", 'return false;');
                    //console.log($(this).attr("href"))
                  }
                 });

             $('#'+row+" a").click(function(){
                if ($(this).attr("href")) {
                    history.pushState({}, "", $(this).attr("href"))
                    var event=$(this).attr("href");
                    var segmenGet=event.split("/").splice(3,5).join("/");
                    var segmenMeta=event.split("/").splice(4,1).join("/");
                    var segmenMetaObj=event.split("/").splice(3,1).join("/");
                    headMeta(segmenMeta);
                    const myRouter = new readRouter(main);
                    return myRouter.template(main,segmenGet,segmenMetaObj);   
                 } 
             });
      });


}

export function getHistory(main) { 
      var segmenGet=$(location).attr('href').split("/").splice(4,10).join("/");
      let nmafile=setSplit(1,'#',segmenGet)
      if (nmafile) {
         if (main.segment=='package') {
            var  getDirektori='pec/'+replace(segmenGet,'#','/') 
         } else {
            var  getDirektori='theme/'+replace(segmenGet,'#','/') 
         }
         routePath(getDirektori,main.atribut);
      }
      if (main.content=='tabline') {
         $("#index").removeClass("active");
         $("#"+nmafile).addClass("active").siblings().removeClass("active"); 
      }
 
}

export function Router(main) { 
 $('a').click(function(){
       var ulr=$(this).attr('href');
       if (ulr !=='javascript:void(0);') {
            history.replaceState('setRhref', '', ulr);
            var segmenGet=$(location).attr('href').split("/").splice(4,5).join("/");
            var segmenGetdevices=$(location).attr('href').split("/").splice(4,1).join("/");
            var nav1=$(location).attr('href').split("/").splice(5,1).join("/");
            // if (true) {} else {}
            if (explode(nav1,'_',1)) {
                var myPackage=segmenGetdevices+'/'+explode(nav1,'_',0);
                var appsetKey=explode(nav1,'_',1);
            } else {
                var myPackage=segmenGet;
                var appsetKey='';
            }
            // console.log(segmenGet)
            headMeta(myPackage);

            if (segmenGetdevices=='') {
                var meta='home';
            } else {
                var meta=segmenGetdevices
            }
          

            $("#"+meta).addClass("active").siblings().removeClass("active"); 
            $("#nav"+meta).addClass("active").siblings().removeClass("active");
            $("#nav1"+nav1).addClass("active").siblings().removeClass("active");
            const myRouter = new readRouter(main);
           
            return myRouter.package(main,myPackage,appsetKey);  
        } 
  });
}

