export function setFrom(type) {
    // console.log(type)
  const myFrom = new From(type.storage,type.action,type.storage,type.storage.content)
  if (type.storage.content=='upload') {
       myFrom.upload(
        type.storage.model,
        type.storage,
        type.storage.content,
        type.storage.model
        )
  } else if (type.storage.content=='uploadFile'){
       myFrom.upload(type.storage.model,type.storage,type.storage.content,type.storage.model)
  } else if (type.storage.content=='userid'){
       myFrom.userid(type.storage.model,type.storage,type.storage.content,type.storage.model)
  } else if (type.storage.content=='codeMirror'){
       myFrom.codeMirror(type.storage.model,type.storage)
  } else if (type.storage.content=='xlsx'){
       myFrom.xlsx(type.storage.model,type.storage)
  } else if (type.storage.content=='firebase'){
       myFrom.firebase(
        type.storage.model,
        type.storage,
        type.action)
  } else if (type.storage.content=='from'){
       myFrom.from(type.storage.model,type.storage)
  } else if (type.storage.content=='office'){
      myFrom.office(type.storage.model,type.storage,type.storage.content,type.storage.model)
  } else if (type.storage.content=='dompdf'){
      myFrom.dompdf(type.storage.model,type.storage,type.storage.content,type.storage.model)
  } else if (type.storage.content=='pridRaw'){
        myFrom.pridRaw(type.storage.model,type.storage) 
  } else {
       myFrom.dialog(type.storage.model,type.storage)
  } 
}

export function setModal(style) {
  // console.log(style);
        count++;
        const addModal = new Modal(
            style.titel, 
            style.width, 
            style.key, 
            style.model,
            style.route,
            style.tabel,
            style.content,
            count,
            style.page,
            style
            );
        // console.log(addModal)
         var resheader =style.content+style.titel.replace(/[^A-Za-z0-9]/g, '')+count;
         if(style.content == 'profil') {
            addModal.profil(style.titel,resheader,style.model)  
         } else if (style.content == 'delete'){
           addModal.delete(style.titel,resheader,style.route,style.page)  
         } else if (style.content == 'recycle'){
           addModal.recycle(style.titel,resheader,style.model,style.page)  

         } else if (style.content == 'restore'){
           addModal.restore(style.titel,resheader,style.model,style.page)  

         } else if (style.content == 'from'){
           addModal.from(style.titel,resheader,style.model)  
           
          } else if (style.content == 'pridRaw'){
           addModal.pridRaw(style.titel,style.model,style.model,style)  
         } else if (style.content == 'fromAction'){
           addModal.fromAction(style.titel,style.model,style.model,style) 
         } else if (style.content == 'upload'){
           addModal.upload(style.titel,resheader,style.model)  
          } else if (style.content == 'office'){
           addModal.office(style.titel,resheader,style.model)  
          } else if (style.content == 'dompdf'){
           
           addModal.dompdf(style.titel,resheader,style.model)  
         } else {
           addModal.modal(style.titel,resheader,style.model,style.content)  
         }        
}









export function setFromTables(type) {
  const myFrom = new FromTables(type.storage,type.action,type.storage,type.storage.content)
  if (type.storage.content=='upload') {
      myFrom.upload(type.storage.model,type.storage,type.storage.content,type.storage.model)
  } else if (type.storage.content=='uploadFile'){
       myFrom.upload(type.storage.model,type.storage,type.storage.content,type.storage.model)
  } else if (type.storage.content=='userid'){
       myFrom.userid(type.storage.model,type.storage,type.storage.content,type.storage.model)
  } else {
       myFrom.from(type.storage.model,type.storage)
  } 
 
}

