function text_shorten(str, length, ending=''){
    if (length == null) {
      length = 10;
    }
    if (ending == null) {
       ending = '...';
    }
    if (str.length > length) {
      return str.substring(0, length - ending.length) + '...';
    } else {
      return str;
    }
  };
