export function setDecode(code,key='') {
    var dcodeset=(typeof(code) === 'number' || typeof(code) === "string" && code.trim() !== '') && !isNaN(code);  
   if (dcodeset==true) {
      return Encode(code);
   } else {
      return Decode(code);
   }
}

